\begin{align*}
&\lim_{n \to \infty} \left( \frac{n + 1}{n^2 + 1} + \frac{n + 2}{n^2 + 4} + \frac{n + 3}{n^2 + 9} + \cdots + \frac{n + n}{n^2 + n^2} \right) = \lim_{n \to \infty} \sum_{i = 1}^{n} \frac{n + i}{n^2 + i^2}\\
=&\lim_{n \to \infty} \sum_{i = 1}^{n} \frac{n^2 + ni}{n^2 + i^2} \cdot \frac{1}{n} = \lim_{n \to \infty} \sum_{i = 1}^{n} \frac{1 + \frac{i}{n}}{1 + \left( \frac{i}{n} \right)^2} \cdot \frac{1}{n} = \int_{0}^{1} \frac{1 + x}{1 + x^2} dx
\end{align*}

