&\leq |C| + \mathrm{e}^{-ax}\int_{0}^{x} |f(t)\mathrm{e}^{at}| \mathrm{d}t \leq |C| + M\mathrm{e}^{-ax}\int_{0}^{x} \mathrm{e}^{at} \mathrm{d}t\\
&=|C| + \frac{M}{a}(1 - \mathrm{e}^{-ax}) \leq |C| + \frac{M}{a}
\end{align*}
