&\text{也可按右边推导：}\\
&=\frac{1}{8}\iint_{D_{xy}}\sqrt{x^{2} + y^{2}}\cdot(x^{2} + y^{2})d\sigma\\
&=\frac{1}{8}\int_{0}^{\pi}d\theta\int_{0}^{2\sin\theta}r^{3}rdr\\
&=\frac{1}{40}\cdot2^{5}\int_{0}^{\pi}\sin^{5}\theta d\theta=\frac{64}{75}
\end{align*}

应填$\frac{4\pi}{15}$.
由轮换对称性可知，$\underset{\Omega }{\iiint }z^{2}\mathrm{d}x\mathrm{d}y\mathrm{d}z = \underset{\Omega }{\iiint }x^{2}\mathrm{d}x\mathrm{d}y\mathrm{d}z = \underset{\Omega }{\iiint }y^{2}\mathrm{d}x\mathrm{d}y\mathrm{d}z$，所以
\begin{align*}
\underset{\Omega }{\iiint }z^{2}\mathrm{d}x\mathrm{d}y\mathrm{d}z&=\frac{1}{3}\underset{\Omega }{\iiint }(x^{2}+y^{2}+z^{2})\mathrm{d}x\mathrm{d}y\mathrm{d}z=\frac{1}{3}\cdot\int_{0}^{2\pi}\mathrm{d}\theta\int_{0}^{\pi}\mathrm{d}\varphi\int_{0}^{1}r^{2}\cdot r^{2}\sin\varphi\mathrm{d}r\\
&=\frac{2\pi}{3}\int_{0}^{\pi}\sin\varphi\mathrm{d}\varphi\int_{0}^{1}r^{4}\mathrm{d}r=\frac{4\pi}{15}
\end{align*}

应填$(\sqrt{2}-1)\pi$.
如图 18-8 所示，从原点引射线穿过 $\Omega$，从 $z = 1$ 穿出，即 $r\cos\varphi = 1$，则 $r = \frac{1}{\cos\varphi}$ 为上限，于是
\begin{align*}
I&=\int_{0}^{2\pi}\mathrm{d}\theta\int_{0}^{\frac{\pi}{4}}\mathrm{d}\varphi\int_{0}^{\frac{1}{\cos\varphi}}\frac{1}{r}\cdot r^{2}\sin\varphi\mathrm{d}r = 2\pi\int_{0}^{\frac{\pi}{4}}\frac{1}{2}r^{2}\big|_{0}^{\frac{1}{\cos\varphi}}\cdot\sin\varphi\mathrm{d}\varphi\\
&=\pi\int_{0}^{\frac{\pi}{4}}\frac{1}{\cos^{2}\varphi}\cdot\sin\varphi\mathrm{d}\varphi = -\pi\int_{0}^{\frac{\pi}{4}}\frac{1}{\cos^{2}\varphi}\mathrm{d}(\cos\varphi) = \pi\cdot\frac{1}{\cos\varphi}\big|_{0}^{\frac{\pi}{4}} = (\sqrt{2}-1)\pi
\end{align*}

\begin{align*}
\int_{L}x\mathrm{d}s&=\int_{0}^{\sqrt{2}}x\sqrt{1+(2x)^{2}}\mathrm{d}x=\frac{1}{8}\int_{0}^{\sqrt{2}}\sqrt{1 + 4x^{2}}\mathrm{d}(1 + 4x^{2})\\
&=\left.\frac{1}{12}(1 + 4x^{2})^{\frac{3}{2}}\right|_{0}^{\sqrt{2}}=\frac{13}{6}
\end{align*}

曲面$\Sigma$在$xOy$坐标面上投影域为$D=\{(x,y)|x^{2} + y^{2} \leq 1\}$. 因为$\frac{\partial z}{\partial x} = 2x$，$\frac{\partial z}{\partial y} = 2y$，所以
\begin{align*}
I&=\iint_{\Sigma}(x - 1)^{3}dydz + (y - 1)^{3}dzdx + (z - 1)dxdy\\
&=\iint_{D}[(x - 1)^{3}\cdot(-2x)+(y - 1)^{3}\cdot(-2y)+(x^{2} + y^{2} - 1)]dxdy\\
&=-\iint_{D}(2x^{4} - 6x^{3} + 5x^{2} - 2x + 2y^{4} - 6y^{3} + 5y^{2} - 2y + 1)dxdy.
\end{align*}
因为区域$D$关于坐标轴对称，所以$\iint_{D}(-6x^{3} - 2x - 6y^{3} - 2y)dxdy = 0$，从而
\begin{align*}
I&=-\iint_{D}(2x^{4} + 5x^{2} + 2y^{4} + 5y^{2} + 1)dxdy\\
&=-\int_{0}^{2\pi}d\theta\int_{0}^{1}[2r^{4}(\cos^{4}\theta + \sin^{4}\theta)+5r^{2} + 1]rdr\\
&=-\int_{0}^{2\pi}\left[\frac{1}{3}(\cos^{4}\theta + \sin^{4}\theta)+\frac{7}{4}\right]d\theta\\
&=-\frac{7\pi}{2}-\frac{8}{3}\int_{0}^{\frac{\pi}{2}}\sin^{4}\theta d\theta=-\frac{7\pi}{2}-\frac{8}{3}\times\frac{3}{4}\times\frac{1}{2}\times\frac{\pi}{2}=-4\pi.
\end{align*}

根据高斯公式，得
\[
I = \underset{\Omega }{\iiint }(2z - xz\sin y + 3y\sin x)\mathrm{d}x\mathrm{d}y\mathrm{d}z
\]
因为$\Omega$关于$xOz$坐标面对称，所以当$y \to -y$时，$\Omega$不变，故$\Omega$关于$xOz$坐标面对称，$\underset{\Omega }{\iiint }xz\sin y\mathrm{d}x\mathrm{d}y\mathrm{d}z = 0$，$\underset{\Omega }{\iiint }3y\sin x\mathrm{d}x\mathrm{d}y\mathrm{d}z = 0$。
记$D = \{ (x, y) | x^{2}+y^{2}\leq 1\}$，则
\begin{align*}
I&=\underset{\Omega }{\iiint }2z\mathrm{d}x\mathrm{d}y\mathrm{d}z = \underset{D}{\iint }\mathrm{d}x\mathrm{d}y\int_{0}^{1 - x}2z\mathrm{d}z\\
&=\underset{D}{\iint }(1 + x^{2})\mathrm{d}x\mathrm{d}y = \pi+\frac{1}{2}\int_{0}^{2\pi}\mathrm{d}\theta\int_{0}^{1}r^{3}\mathrm{d}r = \frac{5\pi}{4}
\end{align*}

由题设得，$I = \underset{\varSigma }{\iint }|xy|z^{2}dxdy + \underset{\varSigma }{\iint }|x|y^{2}z dydz\overset{记}{=}I_{1} + I_{2}$。
\begin{align*}
I_{1}&\overset{高斯公式}{=}\underset{\varOmega }{\iiint }|xy|\cdot 2zdv = \underset{\varOmega }{\iiint }2|xy|zdv\\
&= 8\underset{\substack{\varOmega \\x,y\geq 0}}{\iiint }xyzdv = 8\underset{\substack{x^{2}+y^{2}\leq 1 \\x,y\geq 0}}{\iint }d\sigma\int_{x^{2}+y^{2}}^{1}xyzdv\\
&= 4\underset{\substack{x^{2}+y^{2}\leq 1 \\x,y\geq 0}}{\iint }xy[1 - (x^{2} + y^{2})^{2}]d\sigma\\
&= 4\int_{0}^{\frac{\pi}{2}}d\theta\int_{0}^{1}r^{2}\cos\theta\sin\theta(1 - r^{4})rdr = \frac{1}{4}
\end{align*}
$I_{2}$不能用高斯公式，因$\frac{\partial}{\partial x}(|x|y^{2}z)$在$x = 0$，$yz\neq 0$处不存在。而在点$(x,y,z)$与点$(-x,y,z)$处的通量分别为$|x|y^{2}z dydz$与$|x|y^{2}z(-dydz)$，又在面$z = 1$上$dz = 0$，故$I_{2} = \underset{\varSigma }{\iint }|x|y^{2}z dydz = 0$。于是$I = \frac{1}{4}$。

\textbf{\textcolor{red}{方法一}}
将$L$的方程化为参数形式
\[
\begin{cases}
x = \cos t, \\
y = \sin t, &(0\leq t\leq 2\pi), \\
z = \cos t + \sin t
\end{cases}
\]
则
\begin{align*}
\oint_{L} xz\mathrm{d}x + x\mathrm{d}y + \frac{y^{2}}{2}\mathrm{d}z &= \int_{0}^{2\pi} \left[\cos t\cdot (\cos t + \sin t)\cdot (-\sin t) + \cos t\cdot \cos t + \frac{1}{2}\sin^{2}t\cdot (-\sin t + \cos t)\right]\mathrm{d}t \\
&= \int_{0}^{2\pi} \cos^{2}t\mathrm{d}t = \int_{0}^{2\pi} \frac{1 + \cos 2t}{2}\mathrm{d}t = \pi.
\end{align*}
\textbf{\textcolor{red}{方法二}}
记$S$是平面$z = x + y$上位于柱面$x^{2}+y^{2}=1$内的部分，则$S$在$xOy$平面上的投影为$D = \{(x, y)|x^{2}+y^{2}\leq 1\}$，平面$z = x + y$向上的单位法向量为$\left(-\frac{1}{\sqrt{3}}, -\frac{1}{\sqrt{3}}, \frac{1}{\sqrt{3}}\right)$.
根据斯托克斯公式，得
\begin{align*}
\oint_{L} xz\mathrm{d}x + x\mathrm{d}y + \frac{y^{2}}{2}\mathrm{d}z &= \iint_{S}
\begin{vmatrix}
-\frac{1}{\sqrt{3}} & -\frac{1}{\sqrt{3}} & \frac{1}{\sqrt{3}} \\
\frac{\partial}{\partial x} & \frac{\partial}{\partial y} & \frac{\partial}{\partial z} \\
xz & x & \frac{y^{2}}{2}
\end{vmatrix} \mathrm{d}S \\
&= \iint_{S} \frac{1}{\sqrt{3}}(1 - x - y)\mathrm{d}S \\
&= \iint_{D} \frac{1}{\sqrt{3}}(1 - x - y)\sqrt{3}\mathrm{d}x\mathrm{d}y = \pi.
\end{align*}

先将$L$的方程$x^{2}+y^{2}=a^{2}$代入，得
\begin{align*}
\text{原式}&=\frac{1}{a^{2}}\oint_{L}(e^{x^{2}} - x^{2}y)\mathrm{d}x+(xy^{2}-\sin y^{2})\mathrm{d}y\\
&=\frac{1}{a^{2}}\iint_{x^{2}+y^{2}\leq a^{2}}(x^{2}+y^{2})\mathrm{d}x\mathrm{d}y=\frac{1}{a^{2}}\int_{0}^{2\pi}\mathrm{d}\theta\int_{0}^{a}r^{2}\cdot r\mathrm{d}r=\frac{1}{2}\pi a^{2}
\end{align*}

①函数$xz$在$\Sigma$的$8$个卦限内，$4$正$4$负，且对应点有相同的绝对值，故$\underset{\Sigma }{\iint }xz\mathrm{d}S = 0$；
②根据轮换对称性得到$\underset{\Sigma }{\iint }x^{2}\mathrm{d}S = \underset{\Sigma }{\iint }y^{2}\mathrm{d}S = \underset{\Sigma }{\iint }z^{2}\mathrm{d}S$.
解：
\begin{align*}
\underset{\Sigma }{\iint }x(4x - z)\mathrm{d}S&=\underset{\Sigma }{\iint }4x^{2}\mathrm{d}S\\
&=\frac{4}{3}\underset{\Sigma }{\iint }(x^{2}+y^{2}+z^{2})\mathrm{d}S\\
&=\frac{4}{3}\underset{\Sigma }{\iint }\mathrm{d}S\\
&=\frac{16\pi}{3}
\end{align*}

因为曲面$\Sigma$对称于$yOz$平面，$x$为关于$x$的奇函数，所以$\underset{\Sigma }{\iint }x\mathrm{d}S = 0$. 又因$\Sigma$关于$x,y,z$轮换对称，所以
\begin{align*}
\underset{\Sigma }{\iint }|y|\mathrm{d}S&=\underset{\Sigma }{\iint }|z|\mathrm{d}S=\underset{\Sigma }{\iint }|x|\mathrm{d}S\\
\underset{\Sigma }{\iint }|y|\mathrm{d}S&=\frac{1}{3}\underset{\Sigma }{\iint }(|x|+|y|+|z|)\mathrm{d}S=\frac{1}{3}\underset{\Sigma }{\iint }\mathrm{d}S\\
&=\frac{1}{3}\times A_{\Sigma}
\end{align*}
其中$A_{\Sigma}$为$\Sigma$的面积. 而$\Sigma$由$8$块同样的等边三角形组成，每块等边三角形的边长为$\sqrt{2}$，所以
\[
A_{\Sigma}=8\times\frac{1}{2}\times(\sqrt{2})^2\times\sin\frac{\pi}{3}=4\sqrt{3}
\]
所以$\underset{\Sigma }{\iint }|y|\mathrm{d}S=\frac{4}{3}\sqrt{3}$，从而原式$=\frac{4}{3}\sqrt{3}$.

记$\Omega$是$\Sigma$所围的空间区域.
\begin{align*}
\underset{\Sigma }{\iint }\frac{x^{3}dydz + y^{3}dzdx + z^{3}dxdy}{x^{2}+y^{2}+z^{2}}&=\frac{1}{a^{2}}\underset{\Sigma }{\iint }x^{3}dydz + y^{3}dzdx + z^{3}dxdy=\frac{3}{a^{2}}\underset{\Omega }{\iiint }(x^{2}+y^{2}+z^{2})dxdydz\\
&=\frac{3}{a^{2}}\int_{0}^{2\pi}d\theta\int_{0}^{\pi}d\varphi\int_{0}^{a}r^{4}\sin\varphi dr=\frac{12}{5}\pi a^{3}
\end{align*}
